function dlUrl(url, hops) {
  if ((hops||0)>5) return Promise.reject(new Error('Too many redirects'));
  return new Promise((res,rej)=>{
    const lib=url.startsWith('https')?https:http;
    const req=lib.get(url,{rejectUnauthorized:false},r=>{
      if(r.statusCode===301||r.statusCode===302) return dlUrl(r.headers.location,(hops||0)+1).then(res).catch(rej);
      const c=[];r.on('data',d=>c.push(d));r.on('end',()=>res(Buffer.concat(c)));r.on('error',rej);
    });
    req.on('error',rej);
    req.setTimeout(30000,()=>{req.destroy();rej(new Error('timeout'));});
  });
}

function crc32(buf){
  let c=0xFFFFFFFF;
  for(let i=0;i<buf.length;i++){c^=buf[i];for(let j=0;j<8;j++)c=(c&1)?(0xEDB88320^(c>>>1)):(c>>>1);}
  return(c^0xFFFFFFFF)>>>0;
}

function buildZip(files){
  const parts=[],cds=[];let off=0;
  for(const{name,buf}of files){
    const nb=Buffer.from(name,'utf8');
    const comp=zlib.deflateRawSync(buf,{level:6});
    const crc=crc32(buf);
    const lh=Buffer.alloc(30+nb.length);
    lh.writeUInt32LE(0x04034b50,0);lh.writeUInt16LE(20,4);lh.writeUInt16LE(0,6);
    lh.writeUInt16LE(8,8);lh.writeUInt16LE(0,10);lh.writeUInt16LE(0,12);
    lh.writeUInt32LE(crc,14);lh.writeUInt32LE(comp.length,18);lh.writeUInt32LE(buf.length,22);
    lh.writeUInt16LE(nb.length,26);lh.writeUInt16LE(0,28);nb.copy(lh,30);
    const cd=Buffer.alloc(46+nb.length);
    cd.writeUInt32LE(0x02014b50,0);cd.writeUInt16LE(20,4);cd.writeUInt16LE(20,6);
    cd.writeUInt16LE(0,8);cd.writeUInt16LE(8,10);cd.writeUInt16LE(0,12);cd.writeUInt16LE(0,14);
    cd.writeUInt32LE(crc,16);cd.writeUInt32LE(comp.length,20);cd.writeUInt32LE(buf.length,24);
    cd.writeUInt16LE(nb.length,28);cd.writeUInt16LE(0,30);cd.writeUInt16LE(0,32);
    cd.writeUInt16LE(0,34);cd.writeUInt16LE(0,36);cd.writeUInt32LE(0,38);
    cd.writeUInt32LE(off,42);nb.copy(cd,46);
    parts.push(lh,comp);cds.push(cd);off+=lh.length+comp.length;
  }
  const cdBuf=Buffer.concat(cds);
  const eocd=Buffer.alloc(22);
  eocd.writeUInt32LE(0x06054b50,0);eocd.writeUInt16LE(0,4);eocd.writeUInt16LE(0,6);
  eocd.writeUInt16LE(files.length,8);eocd.writeUInt16LE(files.length,10);
  eocd.writeUInt32LE(cdBuf.length,12);eocd.writeUInt32LE(off,16);eocd.writeUInt16LE(0,20);
  return Buffer.concat([...parts,cdBuf,eocd]);
}

